    &lt;table class="webbtabell"&gt;&lt;tr&gt;&lt;td valign="top" width="99"&gt;&lt;p&gt;&lt;span class="bold "&gt;PROTOKOLL &lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="323"&gt;&lt;p&gt;&lt;span class="bold "&gt;UTSKOTTSSAMMANTRÄDE 20&lt;/span&gt;&lt;span class="bold "&gt;2&lt;/span&gt;&lt;span class="bold "&gt;2&lt;/span&gt;&lt;span class="bold "&gt;/2&lt;/span&gt;&lt;span class="bold "&gt;3&lt;/span&gt;&lt;span class="bold "&gt;:&lt;/span&gt;&lt;span class="bold "&gt;3&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="99"&gt;&lt;p&gt;DATUM&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="323"&gt;&lt;p&gt;2022-10-18&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="99"&gt;&lt;p&gt;TID&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="323"&gt;&lt;p&gt;11.00 – 13.05&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="99"&gt;&lt;p&gt;NÄRVARANDE&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="323"&gt;&lt;p&gt;Se bilaga 1&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;/table&gt;

    &lt;table class="webbtabell"&gt;&lt;tr&gt;&lt;td valign="top" width="28"&gt;&lt;p&gt;&lt;span class="bold "&gt;§ &lt;/span&gt;&lt;span class="bold "&gt;1&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="347" colspan="2"&gt;&lt;p&gt;&lt;span class="bold "&gt;Riksrevisionen informerar om sin granskning: Statens insatser mot invasiva främmande arter (&lt;/span&gt;&lt;span class="bold "&gt;RiR&lt;/span&gt;&lt;span class="bold "&gt; 2022:12) &lt;/span&gt;&lt;/p&gt;

			&lt;p&gt;Riksrevisor Helena Lindberg med medarbetare informerade om Riksrevisionens granskning: Statens insatser mot invasiva främmande arter (RiR 2022:12). &lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="28"&gt;&lt;p&gt;&lt;span class="bold "&gt;§ 2&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="347" colspan="2"&gt;&lt;p&gt;&lt;span class="bold "&gt;Miljö- och jordbruksutskottets tematiska konferens under det svenska ordförandeskapet i EU&lt;/span&gt;&lt;br /&gt;&lt;br /&gt;Utskottet beslutade om en arbetsgrupp för miljö- och jordbruksutskottets tematiska EU23-konferens. I arbetsgruppen deltar: Staffan Eklöf (SD), Helena Storckenfeldt (M), Kajsa Fredholm (V), Stina Larsson (C), Kjell-Arne Ottosson (KD) och Emma Nohrén (MP).&lt;span class="bold "&gt; &lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="28"&gt;&lt;p&gt;&lt;span class="bold "&gt;§ 3&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="347" colspan="2"&gt;&lt;p&gt;&lt;span class="bold "&gt;Beslut om att begära överläggning om översynen av förordning (EU) 2018/841 om utsläpp och upptag av växthusgaser från markanvändning, förändrad markanvändning och skogs&lt;/span&gt;&lt;span class="bold "&gt;bruk (LULUCF)&lt;/span&gt;&lt;/p&gt;

			&lt;p class="bold "&gt;&lt;br /&gt;Utskottet beslutade enligt 7 kap. 12 § RO att begära överläggning med regeringen, Klimat- och näringslivsdepartementet, om &lt;/p&gt;

			&lt;p&gt;COM(2021) 554 Meddelande från kommissionen till Europaparlamentet och rådets förordning om ändring av förordningarna (EU) 2018/841 vad gäller omfattning, förenkling av regler för efterlevnadskontroll, fastställande av medlemsstaternas mål för 2030 och åtaganden för att kollektivt uppnå klimatneutralitet 2035 i sektorn för markanvändning, skogsbruk och jordbruk, och (EU) 2018/1999 vad gäller förbättrad övervakning, rapportering, uppföljning av framsteg och översyn &lt;/p&gt;

			&lt;p&gt;Denna paragraf förklarades omedelbart justerad.&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="28"&gt;&lt;p&gt;&lt;span class="bold "&gt;§ &lt;/span&gt;&lt;span class="bold "&gt;4&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="347" colspan="2"&gt;&lt;p&gt;&lt;span class="bold "&gt;Inbjudan att ingå i den svenska delegationen vid COP15, Konventionen om biologisk mångfald (CBD)&lt;/span&gt;&lt;/p&gt;

			&lt;p&gt;&lt;span class="bold "&gt; &lt;/span&gt;&lt;/p&gt;

			&lt;p&gt;Kanslichefen informerade att 1–2 ledamöter i utskottet är inbjudna att ingå i regeringens delegation vid det 15:e partsmötet inom Konventionen om biologisk mångfald (CBD) och dess protokoll den 7 – 19 december 2022 i Montreal, Kanada. &lt;/p&gt;

			&lt;p&gt;Frågan bordlades. &lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="28"&gt;&lt;p&gt;&lt;span class="bold "&gt;§ &lt;/span&gt;&lt;span class="bold "&gt;5&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="347" colspan="2"&gt;&lt;p&gt;&lt;span class="bold "&gt;Information om kommande sammanträde&lt;/span&gt;&lt;/p&gt;

			&lt;p&gt;Kanslichefen informerade att Jordbruksverkets generaldirektör Christina Nordin kommer till utskottets sammanträde torsdag den 10 november 2022 kl. 10.00 och informerar om Jordbruksverkets arbete.&lt;span class="bold "&gt; &lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="28"&gt;&lt;p&gt;&lt;span class="bold "&gt;§ &lt;/span&gt;&lt;span class="bold "&gt;6&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="347" colspan="2"&gt;&lt;p&gt;&lt;span class="bold "&gt;Sammanträde vid arbetsplenum&lt;/span&gt;&lt;/p&gt;

			&lt;p&gt;Utskottet beslutade att sammanträda samtidigt som arbetsplenum i kammaren.  &lt;/p&gt;

			&lt;p&gt; &lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="28"&gt;&lt;p&gt;&lt;span class="bold "&gt;§ &lt;/span&gt;&lt;span class="bold "&gt;7&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="347" colspan="2"&gt;&lt;p&gt;&lt;span class="bold "&gt;Introduktion till utskottsarbetet                                                  &lt;/span&gt;&lt;/p&gt;

			&lt;p&gt;Kanslichefen gav en introduktion till utskottsarbetet och om arbetsrutiner för EU-information och överläggning. &lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="358" colspan="2"&gt;&lt;p&gt;Vid protokollet&lt;/p&gt;

			&lt;p&gt;Justeras den 25 oktober 2022&lt;/p&gt;

			&lt;p&gt;Emma Nohrén&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;/table&gt;

    &lt;table class="webbtabell border"&gt;&lt;tr&gt;&lt;td valign="top" width="198"&gt;&lt;p&gt;&lt;br /&gt;&lt;br /&gt;MILJÖ- OCH JORDBRUKS- UTSKOTTET&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="163" colspan="8"&gt;&lt;p&gt;&lt;span class="bold "&gt;NÄRVAROFÖRTECKNING&lt;/span&gt;&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="92" colspan="5"&gt;&lt;p&gt;&lt;span class="bold "&gt;Bilaga 1 &lt;/span&gt;till &lt;/p&gt;

			&lt;p&gt;prot. 2022/23:3&lt;/p&gt;

			&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="198"&gt;&lt;/td&gt;&lt;td valign="top" width="43" colspan="2"&gt;&lt;p&gt;§ 1&lt;/p&gt;

