			&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21" colspan="2"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="198"&gt;&lt;p&gt;Martin Kinnunen (SD)&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;p&gt;X&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;p&gt;X&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;p&gt;-&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21" colspan="2"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;/td&gt;&lt;/tr&gt;

		&lt;tr&gt;&lt;td valign="top" width="198"&gt;&lt;p&gt;Lena Bäckelin (S)&lt;/p&gt;

			&lt;/td&gt;&lt;td valign="top" width="21"&gt;&lt;p&gt;X&lt;/p&gt;

